namespace NotificationsApp.Services;

public record Notification(int Id, string Message, DateTime Timestamp);

public class NotificationService
{
    private readonly List<Notification> _notifications;
    private int _nextId;

    public NotificationService()
    {
        _notifications = new List<Notification>
        {
            new(1, "Welcome to the app!", DateTime.UtcNow.AddMinutes(-30)),
            new(2, "Your profile was updated.", DateTime.UtcNow.AddMinutes(-15)),
            new(3, "New feature: dark mode is available.", DateTime.UtcNow.AddMinutes(-5)),
        };
        _nextId = 4;
    }

    public Task<List<Notification>> GetNotificationsAsync()
    {
        lock (_notifications)
        {
            return Task.FromResult(_notifications.OrderByDescending(n => n.Timestamp).ToList());
        }
    }

    public Task<List<Notification>> GetNotificationsSinceAsync(DateTime since)
    {
        lock (_notifications)
        {
            var newer = _notifications
                .Where(n => n.Timestamp > since)
                .OrderByDescending(n => n.Timestamp)
                .ToList();
            return Task.FromResult(newer);
        }
    }

    /// <summary>
    /// Simulates new notifications arriving over time.
    /// Called internally by the polling loop; in a real app this would read from a DB or message queue.
    /// </summary>
    public Task GenerateRandomNotificationAsync()
    {
        var messages = new[]
        {
            "You have a new follower.",
            "Someone commented on your post.",
            "Your report is ready to download.",
            "Server maintenance scheduled tonight.",
            "A teammate mentioned you in a discussion.",
        };

        lock (_notifications)
        {
            var msg = messages[Random.Shared.Next(messages.Length)];
            _notifications.Add(new Notification(_nextId++, msg, DateTime.UtcNow));
        }

        return Task.CompletedTask;
    }
}

@page "/notifications"
@rendermode InteractiveServer
@using NotificationsApp.Services
@inject NotificationService NotificationSvc
@implements IAsyncDisposable

<PageTitle>Notifications</PageTitle>

<h1>
    Notifications
    @if (NotificationList is not null)
    {
        <span class="badge bg-primary rounded-pill ms-2">@NotificationList.Count</span>
    }
</h1>

@if (NotificationList is null)
{
    <p><em>Loading notifications…</em></p>
}
else if (NotificationList.Count == 0)
{
    <p>No notifications yet.</p>
}
else
{
    <ul class="list-group">
        @foreach (var n in NotificationList)
        {
            <li class="list-group-item d-flex justify-content-between align-items-start">
                <span>@n.Message</span>
                <small class="text-muted">@n.Timestamp.ToString("HH:mm:ss")</small>
            </li>
        }
    </ul>
}

@code {
    private CancellationTokenSource? _cts;

    [PersistentState]
    public List<Notification>? NotificationList { get; set; }

    protected override async Task OnInitializedAsync()
    {
        // ??= ensures we only fetch if state wasn't restored from prerender
        NotificationList ??= await NotificationSvc.GetNotificationsAsync();
    }

    protected override void OnAfterRender(bool firstRender)
    {
        // OnAfterRender is NOT called during prerender — only after the
        // interactive runtime attaches, so the polling loop never runs
        // during the static server render.
        if (firstRender)
        {
            _cts = new CancellationTokenSource();
            _ = PollForNotificationsAsync(_cts.Token);
        }
    }

    private async Task PollForNotificationsAsync(CancellationToken ct)
    {
        while (!ct.IsCancellationRequested)
        {
            try
            {
                await Task.Delay(TimeSpan.FromSeconds(5), ct);

                // Simulate a new notification arriving on each poll
                await NotificationSvc.GenerateRandomNotificationAsync();

                var latest = await NotificationSvc.GetNotificationsAsync();
                NotificationList = latest;

                await InvokeAsync(StateHasChanged);
            }
            catch (OperationCanceledException)
            {
                // Expected on disposal — exit cleanly
                break;
            }
        }
    }

    public async ValueTask DisposeAsync()
    {
        if (_cts is not null)
        {
            await _cts.CancelAsync();
            _cts.Dispose();
        }
    }
}

