+    @if (NotificationList is not null)
+    {
+        <span class="badge bg-primary rounded-pill ms-2">@NotificationList.Count</span>
+    }
+</h1>
+
+@if (NotificationList is null)
+{
+    <p><em>Loading notifications…</em></p>
+}
+else if (NotificationList.Count == 0)
+{
+    <p>No notifications yet.</p>
+}
+else
+{
+    <ul class="list-group">
+        @foreach (var n in NotificationList)
+        {
+            <li class="list-group-item d-flex justify-content-between align-items-start">
+                <span>@n.Message</span>
+                <small class="text-muted">@n.Timestamp.ToString("HH:mm:ss")</small>
+            </li>
+        }
+    </ul>
+}
+
+@code {
+    private CancellationTokenSource? _cts;
+
+    [PersistentState]
+    public List<Notification>? NotificationList { get; set; }
+
+    protected override async Task OnInitializedAsync()
+    {
+        // ??= ensures we only fetch if state wasn't restored from prerender
+        NotificationList ??= await NotificationSvc.GetNotificationsAsync();
+    }
+
+    protected override void OnAfterRender(bool firstRender)
+    {
+        // OnAfterRender is NOT called during prerender — only after the
+        // interactive runtime attaches, so the polling loop never runs
+        // during the static server render.
+        if (firstRender)
+        {
+            _cts = new CancellationTokenSource();
+            _ = PollForNotificationsAsync(_cts.Token);
+        }
+    }
+
+    private async Task PollForNotificationsAsync(CancellationToken ct)
+    {
+        while (!ct.IsCancellationRequested)
+        {
+            try
+            {
+                await Task.Delay(TimeSpan.FromSeconds(5), ct);
+
+                // Simulate a new notification arriving on each poll
+                await NotificationSvc.GenerateRandomNotificationAsync();
+
+                var latest = await NotificationSvc.GetNotificationsAsync();
+                NotificationList = latest;
+
+                await InvokeAsync(StateHasChanged);
+            }
+            catch (OperationCanceledException)
+            {
+                // Expected on disposal — exit cleanly
+                break;
+            }
+        }
+    }
+
+    public async ValueTask DisposeAsync()
+    {
+        if (_cts is not null)
+        {
+            await _cts.CancelAsync();
+            _cts.Dispose();
+        }
+    }
+}
