namespace NotificationsApp.Services;

public record Notification(int Id, string Message, DateTime Timestamp);

public class NotificationService
{
    private readonly List<Notification> _notifications;
    private int _nextId;

    public NotificationService()
    {
        _notifications = new List<Notification>
        {
            new(1, "Welcome to the app!", DateTime.UtcNow.AddMinutes(-30)),
            new(2, "Your profile was updated.", DateTime.UtcNow.AddMinutes(-15)),
            new(3, "New feature: dark mode is available.", DateTime.UtcNow.AddMinutes(-5)),
        };
        _nextId = 4;
    }

    public Task<List<Notification>> GetNotificationsAsync()
    {
        lock (_notifications)
        {
            return Task.FromResult(_notifications.OrderByDescending(n => n.Timestamp).ToList());
        }
    }

    public Task<List<Notification>> GetNotificationsSinceAsync(DateTime since)
    {
        lock (_notifications)
        {
            var newer = _notifications
                .Where(n => n.Timestamp > since)
                .OrderByDescending(n => n.Timestamp)
                .ToList();
            return Task.FromResult(newer);
        }
    }

    /// <summary>
    /// Simulates new notifications arriving over time.
    /// In a real app this would read from a DB or message queue.
    /// </summary>
    public Task GenerateRandomNotificationAsync()
    {
        var messages = new[]
        {
            "You have a new follower.",
            "Someone commented on your post.",
            "Your report is ready to download.",
            "Server maintenance scheduled tonight.",
            "A teammate mentioned you in a discussion.",
        };

        lock (_notifications)
        {
            var msg = messages[Random.Shared.Next(messages.Length)];
            _notifications.Add(new Notification(_nextId++, msg, DateTime.UtcNow));
        }

        return Task.CompletedTask;
    }
}

